document.addEventListener("DOMContentLoaded", () => {
setupMobileMenu();
setupTheme();
setupLanguage();
setupRegistrationSessions();
setupFilePreviews();
setupSubmitHandler();
});
function setupMobileMenu() {
const hamburger = document.getElementById("hamburger");
const navMenu = document.getElementById("navMenu");
const navLinks = document.querySelectorAll(".nav-link");
if (hamburger && navMenu) {
hamburger.addEventListener("click", () => {
hamburger.classList.toggle("open");
navMenu.classList.toggle("open");
});
navLinks.forEach(link => {
link.addEventListener("click", () => {
hamburger.classList.remove("open");
navMenu.classList.remove("open");
});
});
}
}
function setupTheme() {
const themeToggleBtn = document.getElementById("themeToggle");
const currentTheme = localStorage.getItem("theme");
if (currentTheme === "light") {
document.body.classList.add("light-mode");
}
if (themeToggleBtn) {
themeToggleBtn.addEventListener("click", () => {
document.body.classList.toggle("light-mode");
const theme = document.body.classList.contains("light-mode") ? "light" : "dark";
localStorage.setItem("theme", theme);
});
}
}
function setupLanguage() {
const langSelect = document.getElementById("langSelect");
let currentLang = localStorage.getItem("language") || "tr";
if (langSelect) {
langSelect.value = currentLang;
langSelect.addEventListener("change", (e) => {
const selectedLang = e.target.value;
localStorage.setItem("language", selectedLang);
updatePageLanguage(selectedLang);
document.documentElement.lang = selectedLang;
updateSelectedSessionDetails(selectedLang);
});
}
updatePageLanguage(currentLang);
}
function updatePageLanguage(lang) {
const translatableElements = document.querySelectorAll("[data-i18n]");
translatableElements.forEach(element => {
const key = element.getAttribute("data-i18n");
if (translations[key] && translations[key][lang]) {
element.textContent = translations[key][lang];
}
});
const nameInput = document.getElementById("regName");
if (nameInput) {
nameInput.placeholder = lang === "tr" ? "Örn: Ahmet Yılmaz" : "e.g. John Doe";
}
const idInput = document.getElementById("regID");
if (idInput) {
idInput.placeholder = lang === "tr" ? "11 Haneli T.C. Kimlik No" : "ID or Passport Number";
}
const emailInput = document.getElementById("regMail");
if (emailInput) {
emailInput.placeholder = lang === "tr" ? "ahmet@example.com" : "john@example.com";
}
const phoneInput = document.getElementById("regPhone");
if (phoneInput) {
phoneInput.placeholder = lang === "tr" ? "+90 (555) 123 4567" : "+1 (555) 123 4567";
}
const addressInput = document.getElementById("regAddress");
if (addressInput) {
addressInput.placeholder = lang === "tr" ? "Fatura ve resmi evrak adresi..." : "Billing & mailing address...";
}
const docFile = document.getElementById("regDoc");
const docPreviewText = document.querySelector("#regDocPreview span");
if (docPreviewText && (!docFile || !docFile.files.length)) {
docPreviewText.textContent = translations["reg_select_file"][lang];
}
const photoFile = document.getElementById("regHeadshot");
const photoPreviewText = document.querySelector("#regHeadshotPreview span");
if (photoPreviewText && (!photoFile || !photoFile.files.length)) {
photoPreviewText.textContent = translations["reg_select_photo"][lang];
}
const idFrontFile = document.getElementById("regIdFront");
const idFrontPreviewText = document.querySelector("#regIdFrontPreview span");
if (idFrontPreviewText && (!idFrontFile || !idFrontFile.files.length)) {
idFrontPreviewText.textContent = translations["reg_select_photo"][lang];
}
const idBackFile = document.getElementById("regIdBack");
const idBackPreviewText = document.querySelector("#regIdBackPreview span");
if (idBackPreviewText && (!idBackFile || !idBackFile.files.length)) {
idBackPreviewText.textContent = translations["reg_select_photo"][lang];
}
}
let selectedSession = null;
function setupRegistrationSessions() {
const sessionSelect = document.getElementById("sessionSelect");
if (!sessionSelect) return;
const lang = localStorage.getItem("language") || "tr";
sessionsData.forEach(session => {
const dates = lang === "tr" ? session.dateTextTR : session.dateTextEN;
const type = lang === "tr" ? session.typeTR : session.typeEN;
const option = document.createElement("option");
option.value = session.id;
option.textContent = `${dates} (${type})`;
sessionSelect.appendChild(option);
});
const urlParams = new URLSearchParams(window.location.search);
const paramSessionId = parseInt(urlParams.get("sessionId"));
if (paramSessionId) {
const found = sessionsData.find(s => s.id === paramSessionId);
if (found) {
sessionSelect.value = paramSessionId;
selectedSession = found;
}
}
if (!selectedSession && sessionsData.length > 0) {
selectedSession = sessionsData[0];
sessionSelect.value = selectedSession.id;
}
updateSelectedSessionDetails(lang);
sessionSelect.addEventListener("change", (e) => {
const selectedId = parseInt(e.target.value);
const found = sessionsData.find(s => s.id === selectedId);
if (found) {
selectedSession = found;
updateSelectedSessionDetails(localStorage.getItem("language") || "tr");
}
});
}
function updateSelectedSessionDetails(lang) {
const title = document.getElementById("selectedSessionTitle");
const price = document.getElementById("selectedSessionPrice");
const container = document.getElementById("selectedSessionDetails");
if (!selectedSession || !container) return;
if (title) {
title.textContent = lang === "tr" ? selectedSession.dateTextTR : selectedSession.dateTextEN;
}
if (price) {
price.textContent = selectedSession.price;
}
const classType = lang === "tr" ? selectedSession.typeTR : selectedSession.typeEN;
const timingLabel = lang === "tr" ? "Zaman Bloğu" : "Time Block";
const timingValue = lang === "tr" ? selectedSession.timingTR : selectedSession.timingEN;
const locationLabel = lang === "tr" ? "Eğitim Konumu" : "Training Venue";
const locationValue = lang === "tr" ? selectedSession.locationTR : selectedSession.locationEN;
const paymentLabel = lang === "tr" ? "IBAN Adresi" : "Payment IBAN";
const paymentValue = lang === "tr" ? selectedSession.paymentTR : selectedSession.paymentEN;
container.innerHTML = `
<div class="detail-item">
<span class="detail-lbl">${lang === "tr" ? "Sınıf Türü" : "Class Type"}</span>
<span class="detail-val" style="color: var(--accent); font-weight: bold;">${classType}</span>
</div>
<div class="detail-item">
<span class="detail-lbl">${timingLabel}</span>
<span class="detail-val">${timingValue}</span>
</div>
<div class="detail-item">
<span class="detail-lbl">${locationLabel}</span>
<span class="detail-val">${locationValue}</span>
</div>
<div class="detail-item">
<span class="detail-lbl">${paymentLabel}</span>
<span class="detail-val" style="font-family: monospace; font-size: 0.8rem; letter-spacing: 0.5px;">${paymentValue}</span>
</div>
`;
}
function setupFilePreviews() {
const docFile = document.getElementById("regDoc");
const docPreviewText = document.querySelector("#regDocPreview span");
if (docFile && docPreviewText) {
docFile.addEventListener("change", (e) => {
if (e.target.files.length > 0) {
docPreviewText.textContent = e.target.files[0].name;
}
});
}
const photoFile = document.getElementById("regHeadshot");
const photoPreviewText = document.querySelector("#regHeadshotPreview span");
if (photoFile && photoPreviewText) {
photoFile.addEventListener("change", (e) => {
if (e.target.files.length > 0) {
photoPreviewText.textContent = e.target.files[0].name;
}
});
}
const idFrontFile = document.getElementById("regIdFront");
const idFrontPreviewText = document.querySelector("#regIdFrontPreview span");
if (idFrontFile && idFrontPreviewText) {
idFrontFile.addEventListener("change", (e) => {
if (e.target.files.length > 0) {
idFrontPreviewText.textContent = e.target.files[0].name;
}
});
}
const idBackFile = document.getElementById("regIdBack");
const idBackPreviewText = document.querySelector("#regIdBackPreview span");
if (idBackFile && idBackPreviewText) {
idBackFile.addEventListener("change", (e) => {
if (e.target.files.length > 0) {
idBackPreviewText.textContent = e.target.files[0].name;
}
});
}
}
function setupSubmitHandler() {
const regForm = document.getElementById("courseRegistrationForm");
const successMessage = document.getElementById("regSuccessMessage");
const successBackBtn = document.getElementById("regSuccessBackBtn");
if (!regForm || !successMessage) return;
regForm.addEventListener("submit", (e) => {
e.preventDefault();
const lang = localStorage.getItem("language") || "tr";
const name = document.getElementById("regName").value;
const idNumber = document.getElementById("regID").value;
const email = document.getElementById("regMail").value;
const phone = document.getElementById("regPhone").value;
const docFile = document.getElementById("regDoc").files[0];
const photoFile = document.getElementById("regHeadshot").files[0];
const idFrontFile = document.getElementById("regIdFront").files[0];
const idBackFile = document.getElementById("regIdBack").files[0];
const openAddress = document.getElementById("regAddress").value;
const docName = docFile ? docFile.name : "-";
const photoName = photoFile ? photoFile.name : "-";
const idFrontName = idFrontFile ? idFrontFile.name : "-";
const idBackName = idBackFile ? idBackFile.name : "-";
const sessionDates = lang === "tr" ? selectedSession.dateTextTR : selectedSession.dateTextEN;
const sessionClass = lang === "tr" ? selectedSession.typeTR : selectedSession.typeEN;
const fileTitle = lang === "tr" ? "SAPMAZ ACADEMY - ONLINE KURS KAYIT FORMUMUZ" : "SAPMAZ ACADEMY - ONLINE COURSE REGISTRATION";
const fileSessionLabel = lang === "tr" ? "Dönem / Sınıf" : "Session / Class";
const filePriceLabel = lang === "tr" ? "Dönem Ücreti" : "Session Fee";
const fileIbanLabel = lang === "tr" ? "IBAN Adresi" : "Payment IBAN";
const fileNameLabel = lang === "tr" ? "Ad Soyad" : "Full Name";
const fileIdLabel = lang === "tr" ? "T.C. Kimlik / Pasaport" : "ID or Passport No";
const fileEmailLabel = lang === "tr" ? "E-Posta Adresi" : "Email Address";
const filePhoneLabel = lang === "tr" ? "Telefon No" : "Phone Number";
const fileDocLabel = lang === "tr" ? "Belge Dosyası" : "Student/Grad File";
const filePhotoLabel = lang === "tr" ? "Vesikalık Dosyası" : "Headshot File";
const fileIdFrontLabel = lang === "tr" ? "Kimlik Ön Yüzü" : "Front of ID File";
const fileIdBackLabel = lang === "tr" ? "Kimlik Arka Yüzü" : "Back of ID File";
const fileAddressLabel = lang === "tr" ? "Açık Adres" : "Open Address";
const fileDateLabel = lang === "tr" ? "Başvuru Tarihi" : "Application Date";
const timestamp = new Date().toLocaleString(lang === "tr" ? "tr-TR" : "en-US");
const registrationReportText = `==================================================
${fileTitle}
==================================================
${fileDateLabel.padEnd(20)} : ${timestamp}
--------------------------------------------------
${fileSessionLabel.padEnd(20)} : ${sessionDates} (${sessionClass})
${filePriceLabel.padEnd(20)} : ${selectedSession.price}
${fileIbanLabel.padEnd(20)} : ${selectedSession.paymentTR}
--------------------------------------------------
${fileNameLabel.padEnd(20)} : ${name}
${fileIdLabel.padEnd(20)} : ${idNumber}
${fileEmailLabel.padEnd(20)} : ${email}
${filePhoneLabel.padEnd(20)} : ${phone}
--------------------------------------------------
${fileDocLabel.padEnd(20)} : ${docName}
${filePhotoLabel.padEnd(20)} : ${photoName}
${fileIdFrontLabel.padEnd(20)} : ${idFrontName}
${fileIdBackLabel.padEnd(20)} : ${idBackName}
--------------------------------------------------
${fileAddressLabel}:
--------------------------------------------------
${openAddress}
==================================================
`;
try {
const blob = new Blob([registrationReportText], { type: "text/plain;charset=utf-8" });
const link = document.createElement("a");
link.href = URL.createObjectURL(blob);
const cleanName = name.trim().toLowerCase().replace(/[^a-z0-9]/g, "_");
link.download = `sapmaz_registration_${cleanName || "request"}.txt`;
document.body.appendChild(link);
link.click();
document.body.removeChild(link);
URL.revokeObjectURL(link.href);
} catch (err) {
console.error("Failed to download registration text file:", err);
}
regForm.style.display = "none";
successMessage.style.display = "block";
const mainContainer = document.querySelector(".news-page");
if (mainContainer) {
mainContainer.scrollIntoView({ behavior: "smooth" });
}
});
if (successBackBtn) {
successBackBtn.addEventListener("click", () => {
window.location.href = "../index.html";
});
}
}